/* =========================================================================================
   SCRIPT 3 - INSERT PRICING DATA
   This script inserts all daily prices data into the paloalto_client.fct_pricing_daily.   
   -- Tickers: IXN, QQQ, IEF, VNQ, GLD, SPY, AGG, VT
   -- Price type: Adjusted Close only
========================================================================================= */

-- IXN: 614 rows (Adj Close only)

-- QQQ: 614 rows (Adj Close only)

-- IEF: 614 rows (Adj Close only)

-- VNQ: 614 rows (Adj Close only)

-- GLD: 614 rows (Adj Close only)

-- SPY: 614 rows (Adj Close only)

-- AGG: 614 rows (Adj Close only)

-- VT: 614 rows (Adj Close only)

-- ============================================================
-- VALIDATION — run after loading to verify row counts
-- ============================================================
SELECT ticker, COUNT(*) AS num_rows, MIN(date) AS first_date, MAX(date) AS last_date
FROM paloalto_client.fct_pricing_daily
GROUP BY ticker
ORDER BY ticker;
